    // FWC format codes = ESC then optional <, ), digits, ending in m. One regex
    // strips them (the A320 CleanANSICodes assumes the x1b4m->mojibake corruption,
    // which our correct \u001b strings do not have).
    private static readonly System.Text.RegularExpressions.Regex AnsiRe =
        new System.Text.RegularExpressions.Regex("\u001b[<)\\d]*m", System.Text.RegularExpressions.RegexOptions.Compiled);

    /// <summary>Cleaned (ANSI-stripped) text for a code, or "" if unknown.</summary>
    public static string GetMessage(long code)
    {
        if (Messages.TryGetValue(code.ToString("D9"), out string? raw))
            return System.Text.RegularExpressions.Regex.Replace(AnsiRe.Replace(raw, ""), "\\s+", " ").Trim();
        return "";
    }

    /// <summary>Raw text (ANSI intact) for a code, or "" if unknown.</summary>
    public static string GetRawMessage(long code)
        => Messages.TryGetValue(code.ToString("D9"), out string? raw) ? raw : "";

    /// <summary>Colour/priority word (Red/Amber/Green/...) via the A320 lookup.</summary>
    public static string GetMessagePriority(long code)
        => EWDMessageLookup.GetMessagePriority(GetRawMessage(code));
}
